var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......아무리 생각해도 모르겠어.","JPN":"……いくら考えても理解できない。","ENG":"I still don’t get it.","TWN":"……我不管怎麼想還是不明白。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"무슨 말이죠, 미나 양?","JPN":"何がですか？　ミナさん。","ENG":"Get what, Mina?","TWN":"不明白什麼，米娜小姐？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서라는 녀석들 말이야.","JPN":"リプレイサーって奴らのことよ。","ENG":"These Replacer guys, I mean.","TWN":"我是說克隆集團的傢伙們。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이런 짓을 해서 사람들을 다 침식체로 만드는 게 대체 무슨 이득이 있다는 거야?","JPN":"こんなことをして人をみんな侵食体にすることに、何のメリットがあるというの？","ENG":"What do they have to gain by turning everyone into C.O.'s like this?","TWN":"他們把人類變成侵蝕體到底有什麼好處？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요.","JPN":"どうでしょう。","ENG":"Beats me.","TWN":"是呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"인간의 수를 줄여서 지구의 환경을 지킨다거나?","JPN":"人間の数を減らして地球の環境を守るとか？","ENG":"Perhaps they want to save the environment by reducing the human population?","TWN":"是要減少人類數量，還是保護地球？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......침식체는 환경에 도움이 되나?","JPN":"……侵食体は環境に役立ってるわけ？","ENG":"Since when were C.O.'s good for the environment?","TWN":"……侵蝕體就對環境有好處嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럴 것 같진...... 않군요.","JPN":"そうは……思えませんね。","ENG":"Well, they might be... or not.","TWN":"應該……也不是那樣吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"침식체가 뿜어내는 침식파 밀도가 높아지면 정상적인 생명체는 살 수가 없으니까요.","JPN":"侵食体の吐く侵食波密度が高くなると、正常な生命体は生存できないですから。","ENG":"I guess high levels of corruption rays won’t provide for a very habitable environment for most lifeforms.","TWN":"侵蝕體釋放出的侵蝕波密度越高，正常生命體的存活率就越低。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 말이야.","JPN":"そう、そこなの。","ENG":"Exactly.","TWN":"確實。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석들도 어쨌든 지구에서 살아가야 하잖아.","JPN":"あいつらも地球で生きていかなければならないじゃない。","ENG":"I mean, even those Replacers will need to find a way to keep surviving.","TWN":"那些傢伙不也要在地球上活下去嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이렇게 지구를 이면세계처럼 바꿔 버린 다음은 어쩔 생각이지?","JPN":"こうやって地球を裏世界のように変えてしまった後は、いったいどうするつもりなんだろう。","ENG":"So what are they going to do after making the entire planet like the Counterside?","TWN":"把地球變成異界後，接下來是要做什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어디 화성 같은 곳으로 이주라도 갈 셈인가?","JPN":"火星や別の星に移住でもするつもりなのかな。","ENG":"Move to Mars or something?","TWN":"打算搬家到火星嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......화성도 별로 살기 좋을 것 같진 않네요.","JPN":"……火星もあまり住みやすいとは思えないですね。","ENG":"Mars doesn’t sound very hospitable either.","TWN":"……火星好像也不怎麼適合生存呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만...... 미나 양이 의외로 정곡을 찌른 걸 수도 있어요.","JPN":"でも、ミナさんが意外に的を射ているかもしれません。","ENG":"But... I think you may have hit the nail on the head.","TWN":"不過……米娜小姐說不定說到重點了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응......?","JPN":"え……？","ENG":"Huh?","TWN":"嗯……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"놈들의 진짜 목적은 어쩌면......","JPN":"奴らの本当の目的は、もしかしたら…。","ENG":"Perhaps their real objective is...","TWN":"那些傢伙的真正目的，大概……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"여기는 카일 웡.","JPN":"こちらカイル・ウォン。","ENG":"Kyle Wong here.","TWN":"這裡是凱爾。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"목표물로 추정되는 대규모 시설을 발견했다.","JPN":"目標物と見られる大規模施設を発見した。","ENG":"I've got eyes on a massive facility, likely to be the target.","TWN":"發現可能為目標的大型設施。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이 통신을 듣는 즉시, 전원 신속히 함선으로 집결하기 바란다.","JPN":"この通信を聞き次第、全員速やかに艦船に集結するように。","ENG":"All operatives, assemble at the ship immediately upon hearing this transmission.","TWN":"聽到這則通信後，請全員迅速到艦船集合。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이런. 벌써 전송기를 발견하다니, 역시 유능한 분들이네요.","JPN":"ほほう、もう伝送機を発見したなんて、やはり有能ですね。","ENG":"Oh, wow. They already found the transmitter? These folks sure are capable.","TWN":"哎呀。已經找到了輸送機。果然是位能幹的人呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럼 갈까요, 미나 양?","JPN":"じゃあ、行きましょうか。ミナさん。","ENG":"Shall we get going then, Mina?","TWN":"我們走吧，米娜小姐？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배! 이야기를 하다가 말면 어떡해?","JPN":"先輩！　話を途中でやめないでよ。","ENG":"Shiyoon! You didn’t finish your sentence!","TWN":"前輩！你話怎麼只說一半啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그냥 개인적인 추측일 뿐입니다.","JPN":"ハハ、ただの個人的な推測に過ぎませんから。","ENG":"Haha, it was just a personal guess, that’s all.","TWN":"哈哈，這單純只是我個人的推測而已。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"정 궁금하시면 이따가 본인들에게 물어보면 되겠네요.","JPN":"どうしても気になるなら、後で本人に尋ねてみたらいいじゃないですか。","ENG":"If you're that curious, you could just ask them yourselves.","TWN":"真的好奇的話，妳待會問本人就行了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 곧 만나게 될 것 같으니까요.","JPN":"どうやら、もうすぐ会えそうですからね。","ENG":"I've got a feeling we’ll be meeting them very soon.","TWN":"反正不久就要見面了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 인자 전송기로 추정되는 적 시설은 약 2Km 전방에 위치하고 있었습니다.","JPN":"リプレイサー・ファクター伝送機と見られる敵の施設は、約2km前方に位置していました。","ENG":"The facility assessed to be the Replacer Factor transmitter is about two clicks out in front of us.","TWN":"推測為克隆因子傳輸機的敵方設備大約位於前方2km處。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"정찰 결과 전송기 자체에는 별다른 무장이 없지만......","JPN":"偵察の結果、伝送機そのものは特に武装してはいないのですが……","ENG":"Based on our findings, the transmitter itself doesn’t seem to be armed...","TWN":"偵查結果顯示，傳輸機本身沒有任何武裝……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......호위 병력이 많군.","JPN":"……護衛が多いんだな。","ENG":"But it must be heavily guarded.","TWN":"……但是警備兵力很多。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 저 바글거리는 게 전부......?","JPN":"まさか、あのうじゃうじゃしているのが全部……？","ENG":"You mean all those things swarming there are guarding the transmitter?","TWN":"那些密密麻麻的全部都是……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"대형 침식체에 중화기를 장착해 놨군요. 누군지 몰라도 아이디어가 좋은데요?","JPN":"大型侵食体に重火器を付けておいたんですね。\\n誰かわかりませんが、良いこと思いつきましたね。","ENG":"Large C.O. armed with heavy firearms. That’s pretty brilliant, actually.","TWN":"給大型侵蝕體配備了重型武器啊。是誰想出了這麼棒的點子？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"놈들의 주요 거점인 만큼 이 정도의 저항은 예측한 바야.","JPN":"奴らの主要拠点なんだし、この程度は想定内よ。","ENG":"That level of resistance is hardly surprising given the key nature of this position.","TWN":"這是這些傢伙的主要據點，會有這樣的兵力也在我的預料之內。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래도 다행인 건 리플레이서 간부들이 없다는 거지.","JPN":"不幸中の幸いなのは、リプレイサーの幹部たちがいないことね。","ENG":"Lucky for us, there are no Replacer officers there.","TWN":"而且慶幸的是，沒有克隆集團的幹部。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"조무래기들뿐이라면 승산이 아주 없는 것도 아니야.","JPN":"雑魚だけなら勝ち目が全くないわけでもないし。","ENG":"If we're just dealing with the small fry, we might actually have a shot here.","TWN":"只有這些小嘍囉的話，我們的勝算並不低。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"좋아. 작전은?","JPN":"よし、作戦は？","ENG":"Very well. What's the plan?","TWN":"很好。作戰計畫呢？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"우선, 나와 카일이 적 병력을 유인할 거야.","JPN":"まず最初に、アタシとカイルが敵の部隊をおびき寄せる。","ENG":"First, Kyle and I will lure the enemy troops away.","TWN":"首先，我和凱爾引開敵人的兵力。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 사이에 펜릴 소대와 경찰 팀이 각자 다른 루트로 리플레이서 인자 전송기에 접근한다.","JPN":"その間、フェンリル小隊と警察チームがそれぞれ異なるルートからリプレイサー・ファクター伝送機に近づくの。","ENG":"In the mean time, Fenrir Squad and the police officers will each take a different route and approach the Replacer Factor transmitter.","TWN":"在此同時，芬里爾小隊和警察小隊按各自的路線接近克隆因子傳輸機。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"먼저 도착한 쪽이 전송기를 격파하면 작전 성공이지.","JPN":"先に着いた方が伝送機を撃破すれば、作戦成功よ。","ENG":"Whoever gets there first can demolish the transmitter. Mission accomplished.","TWN":"先到的那一方破壞傳輸機，任務就成功了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"둘이서 저 많은 놈들을 유인한다고?","JPN":"二人であんなに大勢の敵をおびき寄せるだって？","ENG":"You're going to lure away all of them just between the two of you?","TWN":"就你們兩個引開這麼多敵人嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"위험할 텐데?","JPN":"危険だと思うが。","ENG":"It will be far too dangerous.","TWN":"這樣會很危險吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"위험하기 때문에 우리가 맡는 겁니다.","JPN":"危険だからこそ、僕たちが行くんです。","ENG":"That is precisely why we’ll be doing that.","TWN":"就是因為危險，所以才必須是我們負責。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"가장 위험한 임무를 군기도, 훈련도, 실적도 부족한 민간 용병에게 맡길 순 없으니까요.","JPN":"最も危険な任務だからこそ、軍規の理解も、訓練も、実績も足りない民間の傭兵に任せるわけにはいかないですから。","ENG":"We can’t leave the most dangerous mission to private mercenaries who lack sufficient discipline, training, and track record.","TWN":"最危險的任務是不可能交給軍紀、訓練和業績都不足的民間傭兵的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......모범적인 말을 들은 것 같은데 왜 기분이 나빠지는 거지?","JPN":"……すごくごもっとな言葉だけど、どうして良い気分がしないのかな。","ENG":"Is it me, or did that textbook answer sound somehow offensive?","TWN":"……這話聽起來雖然很有道理，但為什麼心裡有點不太舒服啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 좋게 좋게 생각하세요, 미나 양.","JPN":"ハハ、前向きに考えましょう、ミナさん。","ENG":"Haha... Let’s just let it slide, Mina.","TWN":"哈哈，往好的方面想嘛。米娜小姐。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......뭐, 그쪽 생각이 그렇다면야.","JPN":"……まあ、そっちの考えがそうならいいか。","ENG":"Well, if you insist.","TWN":"……總之，他們的想法是那樣。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"경찰 여러분들은 어떻지?","JPN":"警察の皆さんはどうかな？","ENG":"How about you police officers?","TWN":"那各位警察是怎麼想的呢？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"당연히 문제없습니다.","JPN":"もちろん、異論ありません。","ENG":"We can handle it.","TWN":"當然沒問題。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"차량 하나로 적진 한가운데를 무모하게 돌파하는 건 강소영 경위의 특기니까요.","JPN":"車一台で敵陣のど真ん中に突っ込むのは、マエカワ警部補の特技ですからね。","ENG":"Lieutenant Kang's specialty is in blindly charging right into hostile formations in a measly vehicle.","TWN":"用一輛車勇闖敵陣，正是姜素英警衛的專門領域。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭣하면 누가 먼저 인자 전송기를 파괴하는지 내기라도 하실까요?","JPN":"何なら誰が先にファクター伝送機を破壊するか賭けでもしましょうか。","ENG":"If you’d like to spice things up, we could place a bet on which team will destroy the transmitter first.","TWN":"不然我們要不要打賭，看誰先破壞掉傳輸機？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어...... 저기, 경정님?","JPN":"えっと……あの、警視様？","ENG":"Um... Excuse me, Major?","TWN":"呃……警正大人。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"무슨 말씀을 하시는 건지 잘 모르겠는데요?","JPN":"おっしゃってる意味がよくわかりませんが。","ENG":"I have no idea what you're talking about.","TWN":"妳在說什麼啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"전 카운터도 아닌데 여기 남는 것 아니었나요?","JPN":"私はカウンターでもないので、ここに残るんじゃなかったですか？","ENG":"I’m not even a Counter... Wasn’t I supposed to stay behind?","TWN":"我又不是制裁者，不是應該要留在這裡嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"평소처럼 운전 잘 부탁해, 강소영 경위.","JPN":"いつも通り、運転よろしくね、マエカワ警部補。","ENG":"I’ll be counting on your extraordinary driving skills like always, Lieutenant.","TWN":"那就像平常一樣，駕駛就拜託妳了，姜素英警衛。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님? 제 눈을 보면서 이야기를 좀 하시죠?","JPN":"警視様？　それ、私の目を見ながら話してください。","ENG":"Major? Could you at least look me in the eyes when you say that?","TWN":"警正大人？妳看著我的眼睛說話啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그거 재미있겠군.","JPN":"そいつは面白そうだな。","ENG":"Sounds fun.","TWN":"有意思。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"경찰 여러분께서 설마 지고 난 후에 다른 말 하는 일은 없겠지?","JPN":"警察のお方が負けた後に、シラを切ることはないだろうな？","ENG":"I trust uniformed civil servants like yourselves won’t go back on your word even if you lose, correct?","TWN":"各位警察要是輸了，應該不會找藉口吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"당연합니다! 물론 질 일도 없겠지만요.","JPN":"当然です！　もちろん負けることもないでしょうし。","ENG":"Of course! And we don’t plan on losing either.","TWN":"當然！而且我們也不會輸。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저기요? 잠깐만요?","JPN":"あの～？　ちょっと待って？","ENG":"Excuse me? Hello!","TWN":"那個？等一下好嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......저기요?!!","JPN":"……待ちなさいよ！！","ENG":"Excuse me?!!","TWN":"……喂？！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"후후, 어쩔 수 없군. 펜릴소대, 다들 들었지?","JPN":"ふふ、しょうがないな。フェンリル小隊、聞いたよな？","ENG":"Haha. You leave me no choice then. Did you get all that, Fenrir squad?","TWN":"呵呵，沒辦法了。芬里爾小隊的各位都聽到了吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 내기라면 어쩔 수 없죠.","JPN":"ああ、賭けなら仕方ないですね。","ENG":"Haha, we can’t back down from a bet, can we?","TWN":"哈哈，打賭的話確實沒辦法呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"조금은 진심으로 해야겠는데요?","JPN":"少しは本気モードでやるしかないでしょう。","ENG":"I guess we’ll have to actually put in a little effort this time.","TWN":"看來我得稍微認真點了？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 다들? 왜 갑자기 의욕이 넘치는 건데?","JPN":"ちょ、なに、みんな。なんで急にやる気がみなぎってるの？","ENG":"W-what the? What’s with you all? Why's everyone so motivated all of a sudden?","TWN":"怎、怎麼啦？大家？為什麼突然變得這麼有幹勁啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님의 나쁜 버릇들 중의 하나죠. 내기라면 사족을 못 쓰시거든요.","JPN":"師匠の悪い癖の中の一つです。賭け事には目がないんです。","ENG":"It’s one of the Master’s few vices. She’s a total sucker for betting.","TWN":"這是師父的壞習慣。一打賭就不要命了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그러는 선배도 준비운동을 하고 있는 것 같은데?","JPN":"……そんな先輩も準備運動してない？","ENG":"Says you. You’re the one warming up right now!","TWN":"……但前輩好像也在做暖身運動耶？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네? 그야 당연한 거죠. 내기잖아요?","JPN":"そりゃ、当たり前ですよ。賭けですから。","ENG":"Huh? Well, of course. A bet’s a bet after all.","TWN":"咦？那不是當然的嗎？不就是打賭嘛。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"내기는 했으면 이겨야죠.","JPN":"賭けをするなら、勝つのみです。","ENG":"Bets are meant to be won.","TWN":"要賭就要贏啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 그게 무슨......?","JPN":"いや、それはどういう……？","ENG":"What are you even talking about?","TWN":"不，這算什麼……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지금까지 그런 거 한 적 한 번도 없잖아?","JPN":"今までそんなこと、一度もしてなかったじゃない。","ENG":"I’ve never seen you like this!","TWN":"從以前到現在，你不是都沒做過這種事嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"몰랐다면 기억해 두도록, 신입.","JPN":"知らなかったならよく覚えておけ、新人。","ENG":"Then let this be a learning experience for you, rookie.","TWN":"如果妳不知道的話就給我記好了，新人。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"펜릴 소대의 방침에 작전 실패는 있어도 내기에 지는 일은 없다.","JPN":"フェンリル小隊のポリシーはな、作戦失敗はあっても、賭け事に負けることはない。","ENG":"Fenrir Squad can tolerate failing a mission, but never losing a bet.","TWN":"芬里爾小隊的作戰方針可能會失敗，但是打賭絕不會輸。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다들 준비됐지? 전력으로 간다!","JPN":"みんな、準備いいな？　全力で行くぞ！","ENG":"Everyone ready? Let’s give this all we got!","TWN":"大家準備好了嗎？盡全力上吧！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};